const item = $input.first();

// AI-generated title from the ClickUp task
const title = $('🖼️ Create ClickUp Gallery Task').item.json.name;

// Find the binary property dynamically
const binaryKey = Object.keys(item.binary)[0];
const binary = item.binary[binaryKey];

// Determine the extension
let extension = "";

// 1. Use the provided file extension if available
if (binary.fileExtension) {
  extension = binary.fileExtension.toLowerCase();
}

// 2. Otherwise extract it from the original filename
else if (binary.fileName && binary.fileName.includes(".")) {
  extension = binary.fileName.split(".").pop().toLowerCase();
}

// 3. Otherwise infer it from the MIME type
else if (binary.mimeType && binary.mimeType.startsWith("image/")) {
  extension = binary.mimeType.replace("image/", "").toLowerCase();

  // Normalize common MIME aliases
  if (extension === "jpeg") extension = "jpg";
  if (extension === "svg+xml") extension = "svg";
}

// 4. Final fallback
else {
  extension = "jpg";
}

// Rename the file
binary.fileName = `${title}.${extension}`;

return [item];

